115		/* a/b/c
116		 * ==> invalidate self
117		 * ==> find "a", have it invalidate "b/c"
118		 * a
119		 * ==> invalidate self
120		 * ==> if "a" exists as a subtree, remove it.
121		 */
122		const char *slash;
123		int namelen;
124		struct cache_tree_sub *down;
125	
126	#if DEBUG_CACHE_TREE
127		fprintf(stderr, "cache-tree invalidate <%s>\n", path);
128	#endif
129	
130		if (!it)
131			return 0;
132		slash = strchrnul(path, '/');
133		namelen = slash - path;
134		it->entry_count = -1;
135		if (!*slash) {
136			int pos;
137			pos = cache_tree_subtree_pos(it, path, namelen);
138			if (0 <= pos) {
139				cache_tree_free(&it->down[pos]->cache_tree);
140				free(it->down[pos]);
141				/* 0 1 2 3 4 5
142				 *       ^     ^subtree_nr = 6
143				 *       pos
144				 * move 4 and 5 up one place (2 entries)
145				 * 2 = 6 - 3 - 1 = subtree_nr - pos - 1
146				 */
147				MOVE_ARRAY(it->down + pos, it->down + pos + 1,
148					   it->subtree_nr - pos - 1);
149				it->subtree_nr--;
150			}
151			return 1;
152		}
153		down = find_subtree(it, path, namelen, 0);
154		if (down)
155			do_invalidate_path(down->cache_tree, slash + 1);
156		return 1;
157	}
158	
159	void cache_tree_invalidate_path(struct index_state *istate, const char *path)
160	{
161		if (do_invalidate_path(istate->cache_tree, path))
162			istate->cache_changed |= CACHE_TREE_CHANGED;
163	}
164	
165	/*
166	 * Check whether this_ce and the next entry in the index form a D/F
167	 * conflict ("path" vs "path/file").  Returns the conflicting "path/..."
168	 * name when one is found, or NULL otherwise.
169	 *
170	 * The cache is sorted, so "path/file" sorts after "path" and the
171	 * conflict is usually visible as adjacent entries.  But other entries
172	 * can sort between them -- e.g. "path-internal" sits between "path"
173	 * and "path/file" because '-' (0x2D) precedes '/' (0x2F) -- so when
174	 * the immediately following entry shares our prefix but starts with a
175	 * character that sorts before '/', binary search for "path/" instead.
176	 */
177	static const char *find_df_conflict(struct index_state *istate,
178					    const struct cache_entry *this_ce,
179					    const struct cache_entry *next_ce)
180	{
181		const char *this_name = this_ce->name;
182		const char *next_name = next_ce->name;
183		int this_len = ce_namelen(this_ce);
184		const struct cache_entry *other;
185		struct strbuf probe = STRBUF_INIT;
186		int pos;
187	
188		if (this_len >= ce_namelen(next_ce) ||
189		    next_name[this_len] > '/' ||
190		    strncmp(this_name, next_name, this_len))
191			return NULL;
192	
193		if (next_name[this_len] == '/')
194			return next_name;
195	
196		strbuf_add(&probe, this_name, this_len);
197		strbuf_addch(&probe, '/');
198		pos = index_name_pos_sparse(istate, probe.buf, probe.len);
199		strbuf_release(&probe);
200	
201		if (pos < 0)
202			pos = -pos - 1;
203		if (pos >= (int)istate->cache_nr)
204			return NULL;
205		other = istate->cache[pos];
206		if (ce_namelen(other) > this_len &&
207		    other->name[this_len] == '/' &&
208		    !strncmp(this_name, other->name, this_len))
209			return other->name;
210		return NULL;
211	}
212	
213	static int verify_cache(struct index_state *istate, int flags)
214	{
215		unsigned i, funny;
216		int silent = flags & WRITE_TREE_SILENT;
217	
218		/* Verify that the tree is merged */
219		funny = 0;
220		for (i = 0; i < istate->cache_nr; i++) {
221			const struct cache_entry *ce = istate->cache[i];
222			if (ce_stage(ce)) {
223				if (silent)
224					return -1;
225				if (10 < ++funny) {
226					fprintf(stderr, "...\n");
227					break;
228				}
229				fprintf(stderr, "%s: unmerged (%s)\n",
230					ce->name, oid_to_hex(&ce->oid));
231			}
232		}
233		if (funny)
234			return -1;
235	
236		/* Also verify that the cache does not have path and path/file
237		 * at the same time.  At this point we know the cache has only
238		 * stage 0 entries.
239		 */
240		funny = 0;
241		for (i = 0; i + 1 < istate->cache_nr; i++) {
242			const struct cache_entry *this_ce = istate->cache[i];
243			const struct cache_entry *next_ce = istate->cache[i + 1];
244			const char *conflict_name;
245	
246			conflict_name = find_df_conflict(istate, this_ce, next_ce);
247			if (conflict_name) {
248				if (10 < ++funny) {
249					fprintf(stderr, "...\n");
250					break;
251				}
252				fprintf(stderr, "You have both %s and %s\n",
253					this_ce->name, conflict_name);
254			}
255		}
256		if (funny)
257			return -1;
258		return 0;
259	}
260	
261	static void discard_unused_subtrees(struct cache_tree *it)
262	{
263		struct cache_tree_sub **down = it->down;
264		int nr = it->subtree_nr;
265		int dst, src;
266		for (dst = src = 0; src < nr; src++) {
267			struct cache_tree_sub *s = down[src];
268			if (s->used)
269				down[dst++] = s;
270			else {
271				cache_tree_free(&s->cache_tree);
272				free(s);
273				it->subtree_nr--;
274			}
275		}
276	}
277	
278	int cache_tree_fully_valid(struct cache_tree *it)
279	{
280		int i;
281		if (!it)
282			return 0;
283		if (it->entry_count < 0 ||
284		    !odb_has_object(the_repository->objects, &it->oid,
285				    ODB_HAS_OBJECT_RECHECK_PACKED | ODB_HAS_OBJECT_FETCH_PROMISOR))
286			return 0;
287		for (i = 0; i < it->subtree_nr; i++) {
288			if (!cache_tree_fully_valid(it->down[i]->cache_tree))
289				return 0;
290		}
291		return 1;
292	}
293	
294	static int must_check_existence(const struct cache_entry *ce)
295	{
296		return !(repo_has_promisor_remote(the_repository) && ce_skip_worktree(ce));
297	}
298	
299	static int update_one(struct cache_tree *it,
300			      struct cache_entry **cache,
301			      int entries,
302			      const char *base,
303			      int baselen,
304			      int *skip_count,
305			      int flags)
306	{
307		struct strbuf buffer;
308		int missing_ok = flags & WRITE_TREE_MISSING_OK;
309		int dryrun = flags & WRITE_TREE_DRY_RUN;
310		int repair = flags & WRITE_TREE_REPAIR;
311		int to_invalidate = 0;
312		int i;
313	
314		assert(!(dryrun && repair));
315	
316		*skip_count = 0;
317	
318		/*
319		 * If the first entry of this region is a sparse directory
320		 * entry corresponding exactly to 'base', then this cache_tree
321		 * struct is a "leaf" in the data structure, pointing to the
322		 * tree OID specified in the entry.
323		 */
324		if (entries > 0) {
325			const struct cache_entry *ce = cache[0];
326	
327			if (S_ISSPARSEDIR(ce->ce_mode) &&
328			    ce->ce_namelen == baselen &&
329			    !strncmp(ce->name, base, baselen)) {
330				it->entry_count = 1;
331				oidcpy(&it->oid, &ce->oid);
332				return 1;
333			}
334		}
335	
336		if (0 <= it->entry_count &&
337		    odb_has_object(the_repository->objects, &it->oid,
338				   ODB_HAS_OBJECT_RECHECK_PACKED | ODB_HAS_OBJECT_FETCH_PROMISOR))
339			return it->entry_count;
340	
341		/*
342		 * We first scan for subtrees and update them; we start by
343		 * marking existing subtrees -- the ones that are unmarked
344		 * should not be in the result.
345		 */
346		for (i = 0; i < it->subtree_nr; i++)
347			it->down[i]->used = 0;
348	
349		/*
350		 * Find the subtrees and update them.
351		 */
352		i = 0;
353		while (i < entries) {
354			const struct cache_entry *ce = cache[i];
355			struct cache_tree_sub *sub;
356			const char *path, *slash;
357			int pathlen, sublen, subcnt, subskip;
358	
359			path = ce->name;
360			pathlen = ce_namelen(ce);
361			if (pathlen <= baselen || memcmp(base, path, baselen))
362				break; /* at the end of this level */
363	
364			slash = strchr(path + baselen, '/');
365			if (!slash) {
366				i++;
367				continue;
368			}
369			/*
370			 * a/bbb/c (base = a/, slash = /c)
371			 * ==>
372			 * path+baselen = bbb/c, sublen = 3
373			 */
374			sublen = slash - (path + baselen);
375			sub = find_subtree(it, path + baselen, sublen, 1);
376			if (!sub->cache_tree)
377				sub->cache_tree = cache_tree();
378			subcnt = update_one(sub->cache_tree,
379					    cache + i, entries - i,
380					    path,
381					    baselen + sublen + 1,
382					    &subskip,
383					    flags);
384			if (subcnt < 0)
385				return subcnt;
386			if (!subcnt)
387				die("index cache-tree records empty sub-tree");
388			i += subcnt;
389			sub->count = subcnt; /* to be used in the next loop */
390			*skip_count += subskip;
391			sub->used = 1;
392		}
393	
394		discard_unused_subtrees(it);
395	
396		/*
397		 * Then write out the tree object for this level.
398		 */
399		strbuf_init(&buffer, 8192);
400	
401		i = 0;
402		while (i < entries) {
403			const struct cache_entry *ce = cache[i];
404			struct cache_tree_sub *sub = NULL;
405			const char *path, *slash;
406			int pathlen, entlen;
407			const struct object_id *oid;
408			unsigned mode;
409			int expected_missing = 0;
410			int contains_ita = 0;
411			int ce_missing_ok;
412	
413			path = ce->name;
414			pathlen = ce_namelen(ce);
415			if (pathlen <= baselen || memcmp(base, path, baselen))
416				break; /* at the end of this level */
417	
418			slash = strchr(path + baselen, '/');
419			if (slash) {
420				entlen = slash - (path + baselen);
421				sub = find_subtree(it, path + baselen, entlen, 0);
422				if (!sub)
423					die("cache-tree.c: '%.*s' in '%s' not found",
424					    entlen, path + baselen, path);
425				i += sub->count;
426				oid = &sub->cache_tree->oid;
427				mode = S_IFDIR;
428				contains_ita = sub->cache_tree->entry_count < 0;
429				if (contains_ita) {
430					to_invalidate = 1;
431					expected_missing = 1;
432				}
433			}
434			else {
435				oid = &ce->oid;
436				mode = ce->ce_mode;
437				entlen = pathlen - baselen;
438				i++;
439			}
440	
441			ce_missing_ok = mode == S_IFGITLINK || missing_ok ||
442				!must_check_existence(ce);
443			if (is_null_oid(oid) ||
444			    (!ce_missing_ok &&
445			     !odb_has_object(the_repository->objects, oid,
446					     ODB_HAS_OBJECT_RECHECK_PACKED | ODB_HAS_OBJECT_FETCH_PROMISOR))) {
447				strbuf_release(&buffer);
448				if (expected_missing)
449					return -1;
450				return error("invalid object %06o %s for '%.*s'",
451					mode, oid_to_hex(oid), entlen+baselen, path);
452			}
453	
454			/*
455			 * CE_REMOVE entries are removed before the index is
456			 * written to disk. Skip them to remain consistent
457			 * with the future on-disk index.
458			 */
459			if (ce->ce_flags & CE_REMOVE) {
460				*skip_count = *skip_count + 1;
461				continue;
462			}
463	
464			/*
465			 * CE_INTENT_TO_ADD entries exist in on-disk index but
466			 * they are not part of generated trees. Invalidate up
467			 * to root to force cache-tree users to read elsewhere.
468			 */
469			if (!sub && ce_intent_to_add(ce)) {
470				to_invalidate = 1;
471				continue;
472			}
473	
474			/*
475			 * "sub" can be an empty tree if all subentries are i-t-a.
476			 */
477			if (contains_ita && is_empty_tree_oid(oid, the_repository->hash_algo))
478				continue;
479	
480			strbuf_grow(&buffer, entlen + 100);
481			strbuf_addf(&buffer, "%o %.*s%c", mode, entlen, path + baselen, '\0');
482			strbuf_add(&buffer, oid->hash, the_hash_algo->rawsz);
483	
484	#if DEBUG_CACHE_TREE
485			fprintf(stderr, "cache-tree update-one %o %.*s\n",
486				mode, entlen, path + baselen);
487	#endif
488		}
489	
490		if (repair) {
491			struct object_id oid;
492			hash_object_file(the_hash_algo, buffer.buf, buffer.len,
493					 OBJ_TREE, &oid);
494			if (odb_has_object(the_repository->objects, &oid, ODB_HAS_OBJECT_RECHECK_PACKED))
495				oidcpy(&it->oid, &oid);
496			else
497				to_invalidate = 1;
498		} else if (dryrun) {
499			hash_object_file(the_hash_algo, buffer.buf, buffer.len,
500					 OBJ_TREE, &it->oid);
501		} else if (odb_write_object_ext(the_repository->objects, buffer.buf, buffer.len, OBJ_TREE,
502						&it->oid, NULL, flags & WRITE_TREE_SILENT ? ODB_WRITE_OBJECT_SILENT : 0)) {
503			strbuf_release(&buffer);
504			return -1;
505		}
506	
507		strbuf_release(&buffer);
508		it->entry_count = to_invalidate ? -1 : i - *skip_count;
509	#if DEBUG_CACHE_TREE
510		fprintf(stderr, "cache-tree update-one (%d ent, %d subtree) %s\n",
511			it->entry_count, it->subtree_nr,
512			oid_to_hex(&it->oid));
513	#endif
514		return i;
515	}
516	
517	int cache_tree_update(struct index_state *istate, int flags)
518	{
519		struct odb_transaction *transaction;
520		int skip, i;
521	
522		i = verify_cache(istate, flags);
523	
524		if (i)
525			return i;
526	
527		if (!istate->cache_tree)
528			istate->cache_tree = cache_tree();
529	
530		if (!(flags & WRITE_TREE_MISSING_OK) && repo_has_promisor_remote(the_repository))
531			prefetch_cache_entries(istate, must_check_existence);
532	
533		trace_performance_enter();
534		trace2_region_enter("cache_tree", "update", istate->repo);
535		transaction = odb_transaction_begin(the_repository->objects);
536		i = update_one(istate->cache_tree, istate->cache, istate->cache_nr,
537			       "", 0, &skip, flags);
538		odb_transaction_commit(transaction);
539		trace2_region_leave("cache_tree", "update", istate->repo);
540		trace_performance_leave("cache_tree_update");
541		if (i < 0)
542			return i;
543		istate->cache_changed |= CACHE_TREE_CHANGED;
544		return 0;
545	}
546	
547	static void write_one(struct strbuf *buffer, struct cache_tree *it,
548			      const char *path, int pathlen)
549	{
550		int i;
551	
552		/* One "cache-tree" entry consists of the following:
553		 * path (NUL terminated)
554		 * entry_count, subtree_nr ("%d %d\n")
555		 * tree-sha1 (missing if invalid)
556		 * subtree_nr "cache-tree" entries for subtrees.
557		 */
558		strbuf_grow(buffer, pathlen + 100);
559		strbuf_add(buffer, path, pathlen);
560		strbuf_addf(buffer, "%c%d %d\n", 0, it->entry_count, it->subtree_nr);
561	
562	#if DEBUG_CACHE_TREE
563		if (0 <= it->entry_count)
564			fprintf(stderr, "cache-tree <%.*s> (%d ent, %d subtree) %s\n",
565				pathlen, path, it->entry_count, it->subtree_nr,
566				oid_to_hex(&it->oid));
567		else
568			fprintf(stderr, "cache-tree <%.*s> (%d subtree) invalid\n",
569				pathlen, path, it->subtree_nr);
570	#endif
571	
572		if (0 <= it->entry_count) {
573			strbuf_add(buffer, it->oid.hash, the_hash_algo->rawsz);
574		}
575		for (i = 0; i < it->subtree_nr; i++) {
576			struct cache_tree_sub *down = it->down[i];
577			if (i) {
578				struct cache_tree_sub *prev = it->down[i-1];
579				if (subtree_name_cmp(down->name, down->namelen,
580						     prev->name, prev->namelen) <= 0)
581					die("fatal - unsorted cache subtree");
582			}
583			write_one(buffer, down->cache_tree, down->name, down->namelen);
584		}
585	}
586	
587	void cache_tree_write(struct strbuf *sb, struct cache_tree *root)
588	{
589		trace2_region_enter("cache_tree", "write", the_repository);
590		write_one(sb, root, "", 0);
591		trace2_region_leave("cache_tree", "write", the_repository);
592	}
593	
594	static int parse_int(const char **ptr, unsigned long *len_p, int *out)
595	{
596		const char *s = *ptr;
597		unsigned long len = *len_p;
598		int ret = 0;
599		int sign = 1;
600	
601		while (len && *s == '-') {
602			sign *= -1;
603			s++;
604			len--;
605		}
606	
607		while (len) {
608			if (!isdigit(*s))
609				break;
610			ret *= 10;
611			ret += *s - '0';
612			s++;
613			len--;
614		}
615	
616		if (s == *ptr)
617			return -1;
618	
619		*ptr = s;
620		*len_p = len;
621		*out = sign * ret;
622		return 0;
623	}
624	
625	static struct cache_tree *read_one(const char **buffer, unsigned long *size_p)
626	{
627		const char *buf = *buffer;
628		unsigned long size = *size_p;
629		struct cache_tree *it;
630		int i, subtree_nr;
631		const unsigned rawsz = the_hash_algo->rawsz;
632	
633		it = NULL;
634		/* skip name, but make sure name exists */
635		while (size && *buf) {
636			size--;
637			buf++;
638		}
639		if (!size)
640			goto free_return;
641		buf++; size--;
642		it = cache_tree();
643	
644		if (parse_int(&buf, &size, &it->entry_count) < 0)
645			goto free_return;
646		if (!size || *buf != ' ')
647			goto free_return;
648		buf++; size--;
649		if (parse_int(&buf, &size, &subtree_nr) < 0)
650			goto free_return;
651		if (!size || *buf != '\n')
652			goto free_return;
653		buf++; size--;
654		if (0 <= it->entry_count) {
655			if (size < rawsz)
656				goto free_return;
657			oidread(&it->oid, (const unsigned char *)buf,
658				the_repository->hash_algo);
659			buf += rawsz;
660			size -= rawsz;
661		}
662	
663	#if DEBUG_CACHE_TREE
664		if (0 <= it->entry_count)
665			fprintf(stderr, "cache-tree <%s> (%d ent, %d subtree) %s\n",
666				*buffer, it->entry_count, subtree_nr,
667				oid_to_hex(&it->oid));
668		else
669			fprintf(stderr, "cache-tree <%s> (%d subtrees) invalid\n",
670				*buffer, subtree_nr);
671	#endif
672	
673		/*
674		 * Just a heuristic -- we do not add directories that often but
675		 * we do not want to have to extend it immediately when we do,
676		 * hence +2.
677		 */
678		it->subtree_alloc = subtree_nr + 2;
679		CALLOC_ARRAY(it->down, it->subtree_alloc);
680		for (i = 0; i < subtree_nr; i++) {
681			/* read each subtree */
682			struct cache_tree *sub;
683			struct cache_tree_sub *subtree;
684			const char *name = buf;
685	
686			sub = read_one(&buf, &size);
687			if (!sub)
688				goto free_return;
689			subtree = cache_tree_sub(it, name);
690			subtree->cache_tree = sub;
691		}
692		if (subtree_nr != it->subtree_nr)
693			die("cache-tree: internal error");
694		*buffer = buf;
695		*size_p = size;
696		return it;
697	
698	 free_return:
699		cache_tree_free(&it);
700		return NULL;
701	}
702	
703	struct cache_tree *cache_tree_read(const char *buffer, unsigned long size)
704	{
705		struct cache_tree *result;
706	
707		if (buffer[0])
708			return NULL; /* not the whole tree */
709	
710		trace2_region_enter("cache_tree", "read", the_repository);
711		result = read_one(&buffer, &size);
712		trace2_region_leave("cache_tree", "read", the_repository);
713	
714		return result;
715	}
716	
717	static struct cache_tree *cache_tree_find(struct cache_tree *it, const char *path)
718	{
719		if (!it)
720			return NULL;
721		while (*path) {
722			const char *slash;
723			struct cache_tree_sub *sub;
724	
725			slash = strchrnul(path, '/');
726			/*
727			 * Between path and slash is the name of the subtree
728			 * to look for.
729			 */
730			sub = find_subtree(it, path, slash - path, 0);
731			if (!sub)
732				return NULL;
733			it = sub->cache_tree;
734	
735			path = slash;
736			while (*path == '/')
737				path++;
738		}
739		return it;
740	}
741	
742	static int write_index_as_tree_internal(struct object_id *oid,
743						struct index_state *index_state,
744						int cache_tree_valid,
745						int flags,
746						const char *prefix)
747	{
748		if (flags & WRITE_TREE_IGNORE_CACHE_TREE) {
749			cache_tree_free(&index_state->cache_tree);
750			cache_tree_valid = 0;
751		}
752	
753		if (!cache_tree_valid && cache_tree_update(index_state, flags) < 0)
754			return WRITE_TREE_UNMERGED_INDEX;
755	
756		if (prefix) {
757			struct cache_tree *subtree;
758			subtree = cache_tree_find(index_state->cache_tree, prefix);
759			if (!subtree)
760				return WRITE_TREE_PREFIX_ERROR;
761			oidcpy(oid, &subtree->oid);
762		}
763		else
764			oidcpy(oid, &index_state->cache_tree->oid);
765	
766		return 0;
767	}
768	
769	struct tree *write_in_core_index_as_tree(struct repository *repo,
770						 struct index_state *index_state) {
771		struct object_id o;
772		int was_valid, ret;
773	
774		was_valid = index_state->cache_tree &&
775			    cache_tree_fully_valid(index_state->cache_tree);
776	
777		ret = write_index_as_tree_internal(&o, index_state, was_valid, 0, NULL);
778		if (ret == WRITE_TREE_UNMERGED_INDEX) {
779			int i;
780			bug("there are unmerged index entries:");
781			for (i = 0; i < index_state->cache_nr; i++) {
782				const struct cache_entry *ce = index_state->cache[i];
783				if (ce_stage(ce))
784					bug("%d %.*s", ce_stage(ce),
785					    (int)ce_namelen(ce), ce->name);
786			}
787			BUG("unmerged index entries when writing in-core index");
788		}
789	
790		return lookup_tree(repo, &index_state->cache_tree->oid);
791	}
792	
793	
794	int write_index_as_tree(struct object_id *oid, struct index_state *index_state, const char *index_path, int flags, const char *prefix)
795	{
796		int entries, was_valid;
797		struct lock_file lock_file = LOCK_INIT;
798		int ret;
799	
800		hold_lock_file_for_update(&lock_file, index_path, LOCK_DIE_ON_ERROR);
801	
802		entries = read_index_from(index_state, index_path,
803					  repo_get_git_dir(the_repository));
804		if (entries < 0) {
805			ret = WRITE_TREE_UNREADABLE_INDEX;
806			goto out;
807		}
808	
809		was_valid = !(flags & WRITE_TREE_IGNORE_CACHE_TREE) &&
810			    index_state->cache_tree &&
811			    cache_tree_fully_valid(index_state->cache_tree);
812	
813		ret = write_index_as_tree_internal(oid, index_state, was_valid, flags,
814						   prefix);
815		if (!ret && !was_valid) {
816			write_locked_index(index_state, &lock_file, COMMIT_LOCK);
817			/* Not being able to write is fine -- we are only interested
818			 * in updating the cache-tree part, and if the next caller
819			 * ends up using the old index with unupdated cache-tree part
820			 * it misses the work we did here, but that is just a
821			 * performance penalty and not a big deal.
822			 */
823		}
824	
825	out:
826		rollback_lock_file(&lock_file);
827		return ret;
828	}
829	
830	static void prime_cache_tree_sparse_dir(struct cache_tree *it,
831						struct tree *tree)
832	{
833	
834		oidcpy(&it->oid, &tree->object.oid);
835		it->entry_count = 1;
836	}
837	
838	static void prime_cache_tree_rec(struct repository *r,
839					 struct cache_tree *it,
840					 struct tree *tree,
841					 struct strbuf *tree_path)
842	{
843		struct tree_desc desc;
844		struct name_entry entry;
845		int cnt;
846		size_t base_path_len = tree_path->len;
847	
848		oidcpy(&it->oid, &tree->object.oid);
849	
850		init_tree_desc(&desc, &tree->object.oid, tree->buffer, tree->size);
851		cnt = 0;
852		while (tree_entry(&desc, &entry)) {
853			if (!S_ISDIR(entry.mode))
854				cnt++;
855			else {
856				struct cache_tree_sub *sub;
857				struct tree *subtree = lookup_tree(r, &entry.oid);
858	
859				if (repo_parse_tree(the_repository, subtree) < 0)
860					exit(128);
861				sub = cache_tree_sub(it, entry.path);
862				sub->cache_tree = cache_tree();
863	
864				/*
865				 * Recursively-constructed subtree path is only needed when working
866				 * in a sparse index (where it's used to determine whether the
867				 * subtree is a sparse directory in the index).
868				 */
869				if (r->index->sparse_index) {
870					strbuf_setlen(tree_path, base_path_len);
871					strbuf_add(tree_path, entry.path, entry.pathlen);
872					strbuf_addch(tree_path, '/');
873				}
874	
875				/*
876				 * If a sparse index is in use, the directory being processed may be
877				 * sparse. To confirm that, we can check whether an entry with that
878				 * exact name exists in the index. If it does, the created subtree
879				 * should be sparse. Otherwise, cache tree expansion should continue
880				 * as normal.
881				 */
882				if (r->index->sparse_index &&
883				    index_entry_exists(r->index, tree_path->buf, tree_path->len))
884					prime_cache_tree_sparse_dir(sub->cache_tree, subtree);
885				else
886					prime_cache_tree_rec(r, sub->cache_tree, subtree, tree_path);
887				cnt += sub->cache_tree->entry_count;
888			}
889		}
890	
891		it->entry_count = cnt;
892	}
893	
894	void prime_cache_tree(struct repository *r,
895			      struct index_state *istate,
896			      struct tree *tree)
897	{
898		struct strbuf tree_path = STRBUF_INIT;
899	
900		trace2_region_enter("cache-tree", "prime_cache_tree", r);
901		cache_tree_free(&istate->cache_tree);
902		istate->cache_tree = cache_tree();
903	
904		prime_cache_tree_rec(r, istate->cache_tree, tree, &tree_path);
905		strbuf_release(&tree_path);
906		istate->cache_changed |= CACHE_TREE_CHANGED;
907		trace2_region_leave("cache-tree", "prime_cache_tree", r);
908	}
909	
910	/*
911	 * find the cache_tree that corresponds to the current level without
912	 * exploding the full path into textual form.  The root of the
913	 * cache tree is given as "root", and our current level is "info".
914	 * (1) When at root level, info->prev is NULL, so it is "root" itself.
915	 * (2) Otherwise, find the cache_tree that corresponds to one level
916	 *     above us, and find ourselves in there.
917	 */
918	static struct cache_tree *find_cache_tree_from_traversal(struct cache_tree *root,
919								 struct traverse_info *info)
920	{
921		struct cache_tree *our_parent;
922	
923		if (!info->prev)
924			return root;
925		our_parent = find_cache_tree_from_traversal(root, info->prev);
926		return cache_tree_find(our_parent, info->name);
927	}
928	
929	int cache_tree_matches_traversal(struct cache_tree *root,
930					 struct name_entry *ent,
931					 struct traverse_info *info)
932	{
933		struct cache_tree *it;
934	
935		it = find_cache_tree_from_traversal(root, info);
936		it = cache_tree_find(it, ent->path);
937		if (it && it->entry_count > 0 && oideq(&ent->oid, &it->oid))
938			return it->entry_count;
939		return 0;
940	}
941	
942	static int verify_one_sparse(struct index_state *istate,
943				     struct strbuf *path,
944				     int pos)
945	{
946		struct cache_entry *ce = istate->cache[pos];
947		if (!S_ISSPARSEDIR(ce->ce_mode))
948			return error(_("directory '%s' is present in index, but not sparse"),
949				     path->buf);
950		return 0;
951	}
952	
953	/*
954	 * Returns:
955	 *  0 - Verification completed.
956	 *  1 - Restart verification - a call to ensure_full_index() freed the cache
957	 *      tree that is being verified and verification needs to be restarted from
958	 *      the new toplevel cache tree.
959	 *  -1 - Verification failed.
960	 */
961	static int verify_one(struct repository *r,
962			      struct index_state *istate,
963			      struct cache_tree *it,
964			      struct strbuf *path)
965	{
966		int i, pos, len = path->len;
967		struct strbuf tree_buf = STRBUF_INIT;
968		struct object_id new_oid;
969		int ret;
970	
971		for (i = 0; i < it->subtree_nr; i++) {
972			strbuf_addf(path, "%s/", it->down[i]->name);
973			ret = verify_one(r, istate, it->down[i]->cache_tree, path);
974			if (ret)
975				goto out;
976	
977			strbuf_setlen(path, len);
978		}
979	
980		if (it->entry_count < 0 ||
981		    /* no verification on tests (t7003) that replace trees */
982		    lookup_replace_object(r, &it->oid) != &it->oid) {
983			ret = 0;
984			goto out;
985		}
986	
987		if (path->len) {
988			/*
989			 * If the index is sparse and the cache tree is not
990			 * index_name_pos() may trigger ensure_full_index() which will
991			 * free the tree that is being verified.
992			 */
993			int is_sparse = istate->sparse_index;
994			pos = index_name_pos(istate, path->buf, path->len);
995			if (is_sparse && !istate->sparse_index) {
996				ret = 1;
997				goto out;
998			}
999	
1000			if (pos >= 0) {
1001				ret = verify_one_sparse(istate, path, pos);
1002				goto out;
1003			}
1004	
1005			pos = -pos - 1;
1006		} else {
1007			pos = 0;
1008		}
1009	
1010		if (it->entry_count + pos > istate->cache_nr) {
1011			ret = error(_("corrupted cache-tree has entries not present in index"));
1012			goto out;
1013		}
1014	
1015		i = 0;
1016		while (i < it->entry_count) {
1017			struct cache_entry *ce = istate->cache[pos + i];
1018			const char *slash;
1019			struct cache_tree_sub *sub = NULL;
1020			const struct object_id *oid;
1021			const char *name;
1022			unsigned mode;
1023			int entlen;
1024	
1025			if (ce->ce_flags & (CE_STAGEMASK | CE_INTENT_TO_ADD | CE_REMOVE)) {
1026				ret = error(_("%s with flags 0x%x should not be in cache-tree"),
1027					    ce->name, ce->ce_flags);
1028				goto out;
1029			}
1030	
1031			name = ce->name + path->len;
1032			slash = strchr(name, '/');
1033			if (slash) {
1034				entlen = slash - name;
1035	
1036				sub = find_subtree(it, ce->name + path->len, entlen, 0);
1037				if (!sub || sub->cache_tree->entry_count < 0) {
1038					ret = error(_("bad subtree '%.*s'"), entlen, name);
1039					goto out;
1040				}
1041	
1042				oid = &sub->cache_tree->oid;
1043				mode = S_IFDIR;
1044				i += sub->cache_tree->entry_count;
1045			} else {
1046				oid = &ce->oid;
1047				mode = ce->ce_mode;
1048				entlen = ce_namelen(ce) - path->len;
1049				i++;
1050			}
1051			strbuf_addf(&tree_buf, "%o %.*s%c", mode, entlen, name, '\0');
1052			strbuf_add(&tree_buf, oid->hash, r->hash_algo->rawsz);
1053		}
1054	
1055		hash_object_file(r->hash_algo, tree_buf.buf, tree_buf.len, OBJ_TREE,
1056				 &new_oid);
1057	
1058		if (!oideq(&new_oid, &it->oid)) {
1059			ret = error(_("cache-tree for path %.*s does not match. "
1060				      "Expected %s got %s"), len, path->buf,
1061				    oid_to_hex(&new_oid), oid_to_hex(&it->oid));
1062			goto out;
1063		}
1064	
1065		ret = 0;
1066	out:
1067		strbuf_setlen(path, len);
1068		strbuf_release(&tree_buf);
1069		return ret;
1070	}
1071	
1072	int cache_tree_verify(struct repository *r, struct index_state *istate)
1073	{
1074		struct strbuf path = STRBUF_INIT;
1075		int ret;
1076	
1077		if (!istate->cache_tree) {
1078			ret = 0;
1079			goto out;
1080		}
1081	
1082		ret = verify_one(r, istate, istate->cache_tree, &path);
1083		if (ret < 0)
1084			goto out;
1085		if (ret > 0) {
1086			strbuf_reset(&path);
1087	
1088			ret = verify_one(r, istate, istate->cache_tree, &path);
1089			if (ret < 0)
1090				goto out;
1091			if (ret > 0)
1092				BUG("ensure_full_index() called twice while verifying cache tree");
1093		}
1094	
1095		ret = 0;
1096	
1097	out:
1098		strbuf_release(&path);
1099		return ret;
1100	}
